import android.content.Context
import android.security.keystore.KeyGenParameterSpec
import android.security.keystore.KeyProperties
import androidx.security.crypto.EncryptedSharedPreferences
import java.util.*

class AuthManager(private val context: Context) {
    private lateinit var sharedPreferences: EncryptedSharedPreferences

    init {
        val key = "auth_manager_key"
        val spec = KeyGenParameterSpec.Builder(
            key,
            KeyProperties.PURPOSE_ENCRYPT | KeyProperties.PURPOSE_DECRYPT
        ).apply {
            setEncryptionPreset(KeyProperties.ENCRYPTION_MODE_AES256_GCM)
        }.build()

        try {
            val keyStore = context.getSystemService(Context.KEYSTORE_SERVICE) as android.security.KeyStore
            if (!keyStore.contains(key)) {
                keyStore.generateKey(spec)
            }
            sharedPreferences = EncryptedSharedPreferences.create(
                "auth_manager",
                key,
                context,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            )
        } catch (e: Exception) {
            throw RuntimeException("Failed to create keystore-backed storage", e)
        }
    }

    fun saveAuthToken(token: String, userId: String) {
        sharedPreferences.edit().putString("auth_token", token).apply()
        sharedPreferences.edit().putString("user_id", userId).apply()
    }

    fun getAuthToken(): String? = sharedPreferences.getString("auth_token", null)

    fun getUserID(): String? = sharedPreferences.getString("user_id", null)
